Code:
public int blackjack(int a, int b) {
    // Check if both values are over 21
    if (a > 21 && b > 21) {
        return 0;
    } else if (a > 21) {
        return b;
    } else if (b > 21) {
        return a;
    } else {
        // Find the value closest to 21 without going over
        if (21 - a < 21 - b) {
            return a;
        } else {
            return b;
        }
    }
}

