Code:
public boolean evenlySpaced(int a, int b, int c)
{
    int max = Math.max(Math.max(a, b), c);
    int min = Math.min(Math.min(a, b), c);
    int med = a + b + c - max - min;
    return (max - med) == (med - min);
}

