Code:
public int[] zeroMax(int[] nums) {
    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 0) {
            int maxOdd = findMaxOdd(nums, i);
            if (maxOdd > 0) {
                nums[i] = maxOdd;
            }
        }
    }
    return nums;
}

private int findMaxOdd(int[] nums, int startPos) {
    int maxOdd = 0;
    for (int i = startPos + 1; i < nums.length; i++) {
        if (nums[i] % 2 != 0 && nums[i] > maxOdd) {
            maxOdd = nums[i];
        }
    }
    return maxOdd;
}

