public int[] withoutTen(int[] nums) {
    int[] result = new int[nums.length];
    int nonTenPointer = 0;

    for (int num : nums) {
        if (num != 10) {
            result[nonTenPointer] = num;
            nonTenPointer++;
        }
    }

    // Fill remaining positions with zeros
    while (nonTenPointer < result.length) {
        result[nonTenPointer] = 0;
        nonTenPointer++;
    }

    return result;
}

