Code:
public boolean evenlySpaced(int a, int b, int c) {
    int small, medium, large;

    // Find the smallest value
    if (a <= b && a <= c) {
        small = a;
        medium = (b <= c) ? b : c;
        large = (medium == b) ? c : b;
    } else if (b <= a && b <= c) {
        small = b;
        medium = (a <= c) ? a : c;
        large = (medium == a) ? c : a;
    } else {
        small = c;
        medium = (a <= b) ? a : b;
        large = (medium == a) ? b : a;
    }

    return (medium - small == large - medium);
}

