public int[] seriesUp(int n) {
    if (n <= 0) {
        return new int[]{};
    }

    int[] result = new int[n * (n + 1) / 2];
    int index = 0;

    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= i; j++) {
            result[index] = j;
            index++;
        }
    }

    return result;
}

