public int countClumps(int[] nums) {
    if (nums == null || nums.length == 0) {
        return 0; // Handling edge case of an empty array
    }

    int clumpCount = 0;
    boolean inClump = false;

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] == nums[i - 1]) {
            if (!inClump) {
                inClump = true;
                clumpCount++;
            }
        } else {
            inClump = false;
        }
    }

    return clumpCount;
}

