Code:
public int[] withoutTen(int[] nums) {
    int[] result = new int[nums.length];
    int nonTenIndex = 0;

    for (int num : nums) {
        if (num != 10) {
            result[nonTenIndex] = num;
            nonTenIndex++;
        }
    }

    // Fill the remaining spaces with zeroes
    for (int i = nonTenIndex; i < nums.length; i++) {
        result[i] = 0;
    }

    return result;
}

