Code:
public int centeredAverage(int[] nums) {
    int sum = 0;
    int min = nums[0];
    int max = nums[0];

    for (int num : nums) {
        sum += num;
        min = Math.min(min, num);
        max = Math.max(max, num);
    }

    sum -= min;
    sum -= max;

    return sum / (nums.length - 2);
}

