Code:
public String plusOut(String str, String word) {
    StringBuilder result = new StringBuilder();
    int wordLength = word.length();
    int i = 0;

    while (i < str.length()) {
        if (i <= str.length() - wordLength && str.substring(i, i + wordLength).equals(word)) {
            result.append(word);
            i += wordLength;
        } else {
            result.append("+");
            i++;
        }
    }

    return result.toString();
}

