public int makeChocolate(int small, int big, int goal) {
  int maxBig = goal / 5;
  int bigBarsUsed = Math.min(maxBig, big);
  int remainingGoal = goal - (bigBarsUsed * 5);

  if (remainingGoal <= small) {
    return remainingGoal;
  }

