public int centeredAverage(int[] nums) {
    int min = Integer.MAX_VALUE;
    int max = Integer.MIN_VALUE;
    int sum = 0;

    for (int num : nums) {
        sum += num;
        min = Math.min(min, num);
        max = Math.max(max, num);
    }

    sum -= min;
    sum -= max;

    int count = nums.length - 2; // Ignore one instance of min and max

    return sum / count;
}

