public int countClumps(int[] nums)
{
    int count = 0;
    boolean isClump = false;

    for (int i = 0; i < nums.length - 1; i++) {
        if (nums[i] == nums[i + 1]) {
            if (!isClump) {
                isClump = true;
                count++;
            }
        } else {
            isClump = false;
        }
    }

    return count;
}

